+{
+  "$schema": "https://json-schema.org/draft/2020-12/schema",
+  "$id": "https://wezterm-automata.dev/schemas/wa-robot-agents-running.json",
+  "title": "WA Robot Agents Running Response",
+  "description": "Schema for the data field when calling 'wa robot agents running'. Returns running-agent inventory keyed by pane plus the same inventory summary rollup.",
+  "type": "object",
+  "required": ["running_agents", "summary"],
+  "properties": {
+    "running_agents": {
+      "type": "object",
+      "description": "Running agent inventory keyed by pane_id string",
+      "additionalProperties": {
+        "$ref": "#/$defs/running_agent"
+      }
+    },
+    "summary": {
+      "$ref": "#/$defs/summary",
+      "description": "Rollup counts for the installed and running inventory"
+    }
+  },
+  "additionalProperties": false,
+  "$defs": {
+    "running_agent": {
+      "type": "object",
+      "description": "Single running-agent inventory record",
+      "required": ["slug", "state", "source"],
+      "properties": {
+        "slug": {
+          "type": "string",
+          "description": "Canonical agent/provider slug"
+        },
+        "state": {
+          "type": "string",
+          "description": "Current inferred runtime state"
+        },
+        "session_id": {
+          "type": ["string", "null"],
+          "description": "Agent session identifier if one was extracted"
+        },
+        "source": {
+          "type": "string",
+          "enum": ["pattern_engine", "pane_title", "process_name"],
+          "description": "Source used to infer the running agent identity"
+        }
+      },
+      "additionalProperties": false
+    },
+    "summary": {
+      "type": "object",
+      "description": "Aggregate counts for installed and running agent inventory",
+      "required": ["installed", "running", "configured", "installed_but_idle"],
+      "properties": {
+        "installed": {
+          "type": "integer",
+          "minimum": 0,
+          "description": "Installed agents positively detected on disk"
+        },
+        "running": {
+          "type": "integer",
+          "minimum": 0,
+          "description": "Running agents currently inferred from panes"
+        },
+        "configured": {
+          "type": "integer",
+          "minimum": 0,
+          "description": "Installed agents with an associated configuration path"
+        },
+        "installed_but_idle": {
+          "type": "integer",
+          "minimum": 0,
+          "description": "Installed agents not currently inferred as running"
+        }
+      },
+      "additionalProperties": false
+    }
+  }
+}

